%[text] Now one can proceed to formulate the general optimisation formula:number of patients recruited per IMD is 
%[text]{"align":"center"} $%% Optimization Problem\n\n% Objective:\n\\\[\n\\text{min} \\quad \n\\left\\| X \\right\\|\_0\n- \\| y \\|\_1 \n+ \\left\\| U \\right\\|\_0 \n+ \\left\\| H \\right\\|\_0 \n+ \\rho(\\| \\beta \\|\_1 \n+ \\| \\gamma \\|\_1)\n+ \\| W \\|\_1 \n+ \\| F \\|\_1 \n\\\]\n$
%[text]{"align":"center"} $% Subject to:\n\\text{s.t:}\n\\\[\n\\text{diag(vec}(\\mathbf{D})) \\cdot \\text{vec}(X) = \\text{vec}(Y),\n\\\]\n\\\[\n(\\mathbf{{1}\_{n}^{\\mathrm{T}} \\otimes I\_{m}}) \\cdot \\mathrm{vec}(Y) = y\n\\\]\n\\\[\n(\\mathbf{{1}\_{m}^{\\mathrm{T}} \\otimes I\_{n}}) \\cdot \\mathbf{K\_{mn}} \\cdot \\mathrm{vec}(Y) = z\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{T}) \\cdot \\text{vec}(U) \\geq 2\\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{G}) \\cdot \\text{vec}(H) \\geq 2\\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{B}) \\cdot \\mathbf{L} \\cdot y = \\text{vec}(S),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{r}) \\cdot \\text{vec}(U) = \\text{vec}(\\beta),\n\\\]\n\\\[\n(\\mathbf{I}\_m \\otimes \\mathbf{a}) \\cdot \\text{vec}(H) = \\text{vec}(\\gamma),\n\\\]\n\\\[\n\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)-\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.q)}}}}\\cdotp\\mathbf{K}\_{qm}\\cdotp\\mathrm{vec}(U) \\leq \\text{vec}(F),\n\\\]\n\\\[\n-\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)+\\mathbf{\\mathbf{A\_{\\mathit{(m.t)\\times(m.q)}}}}\\cdotp\\mathbf{K}\_{qm}\\cdotp\\mathrm{vec}(U) \\leq \\text{vec}(F),\n\\\]\n\\\[\n\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)-\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.w)}}}}\\cdotp\\mathbf{K}\_{wm}\\cdotp\\mathrm{vec}(H) \\leq \\text{vec}(W),\n\\\]\n\\\[\n-\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.n)}}}}\\cdotp\\mathrm{vec}(Y)+\\mathbf{\\mathbf{A\_{\\mathit{(m.g)\\times(m.w)}}}}\\cdotp\\mathbf{K}\_{wm}\\cdotp\\mathrm{vec}(H) \\leq \\text{vec}(W),\n\\\]\n\\\[\n0 \\leq X \\leq 1,\n\\\]\n\\\[\nlb\_y \\leq y \\leq ub\_y,\n\\\]\n\\\[\nlb\_z \\leq z \\leq ub\_z.\n\\\]\n$
% Defining left hand-side matrix
% Define a cap for analysis capacity for each omics site
P_u = kron(ones(m, 1)', eye(q));
P_h = kron(ones(m, 1)', eye(w));
clear problem
