% title('Optimisation Gain vs Heuristic (HCP Engagement)', 'Units', 'normalized', 'FontWeight', 'normal');

legend('Optimisation Gain', 'Heuristic', 'Global Greedy', 'Cardinality-Optimised Model', ... %[output:7bd18e9d]
       'Location', 'northwest'); %[output:7bd18e9d]
