b(3).FaceColor = [0.00 0.60 0.50];   % Teal  – Optimised %[output:1950c7d4]

ylabel('Cost (thousand euros)');  % <-- scaled axis %[output:1950c7d4]
set(gca, 'XTick', x, 'XTickLabel', labels); %[output:1950c7d4]

legend('Heuristic', 'Global Greedy', 'Recruitment and Allocation Model', ... %[output:1950c7d4]
       'Location', 'northwest'); %[output:1950c7d4]

ylim([0, max(cost_k(:)) * 1.15]); %[output:1950c7d4]
