        text(x_endpoints(j), y_endpoints(j) + yoff, sprintf('%.1f', values(j)), ... %[output:1950c7d4]
            'HorizontalAlignment', 'center', 'VerticalAlignment', 'bottom', 'FontSize', 10); %[output:1950c7d4]
